 1→import React, { useState } from 'react';
 2→import { CategoryScore } from '../types';
 3→import { ChevronDown, ChevronUp, CheckCircle, AlertTriangle, XCircle } from 'lucide-react';
 4→
 5→interface CategoryCardProps {
 6→  category: CategoryScore;
 7→  simple?: boolean;
 8→}
 9→
10→const CategoryCard: React.FC<CategoryCardProps> = ({ category, simple = false }) => {
11→  const [isExpanded, setIsExpanded] = useState(false);
12→
13→  const getStatusIcon = (status: 'success' | 'warning' | 'error') => {
14→    switch (status) {
15→      case 'success': return <CheckCircle size={18} className="text-purple-400" />;
16→      case 'warning': return <AlertTriangle size={18} className="text-purple-500" />;
17→      case 'error': return <XCircle size={18} className="text-red-500" />;
18→    }
19→  };
20→
21→  const getScoreColor = (score: number) => {
22→    if (score >= 80) return 'text-purple-300';
23→    if (score >= 60) return 'text-purple-400';
24→    return 'text-red-400';
25→  };
26→
27→  return (
28→    <div className={`glass-panel rounded-xl overflow-hidden mb-4 transition-all duration-300 hover:bg-purple-500/5 ${simple ? '' : 'cursor-pointer'}`}>
29→      <div 
30→        className="p-4 flex items-center justify-between"
31→        onClick={() => !simple && setIsExpanded(!isExpanded)}
32→      >
33→        <div className="flex items-center gap-4">
34→          <div className={`w-12 h-12 rounded-full flex items-center justify-center bg-purple-500/5 font-bold ${getScoreColor(category.score)}`}>
35→            {category.score}
36→          </div>
37→          <div>
38→            <h3 className="font-semibold text-lg">{category.name}</h3>
39→            <p className="text-sm text-gray-400">{category.items.length} critères analysés</p>
40→          </div>
41→        </div>
42→        {!simple && (
43→          <button className="text-gray-400 hover:text-white">
44→            {isExpanded ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
45→          </button>
46→        )}
47→      </div>
48→      
49→      {!simple && isExpanded && (
50→        <div className="px-4 pb-4 border-t border-white/5 bg-black/20">
51→          <div className="mt-3 space-y-3">
52→            {category.items.map((item, idx) => (
53→              <div key={idx} className="flex items-start gap-3 text-sm p-2 rounded hover:bg-purple-500/5">
54→                <span className="mt-0.5">{getStatusIcon(item.status)}</span>
55→                <span className="text-gray-300">{item.message}</span>
56→              </div>
57→            ))}
58→          </div>
59→        </div>
60→      )}
61→    </div>
62→  );
63→};
64→
65→export default CategoryCard;

 1→import React, { useEffect, useState } from 'react';
 2→
 3→interface ScoreRingProps {
 4→  score: number;
 5→  size?: number;
 6→  strokeWidth?: number;
 7→  noAnimation?: boolean;
 8→}
 9→
10→const ScoreRing: React.FC<ScoreRingProps> = ({ score, size = 120, strokeWidth = 8, noAnimation = false }) => {
11→  const [animatedScore, setAnimatedScore] = useState(noAnimation ? score : 0);
12→  const radius = (size - strokeWidth) / 2;
13→  const circumference = radius * 2 * Math.PI;
14→  const offset = circumference - (animatedScore / 100) * circumference;
15→
16→  useEffect(() => {
17→    if (noAnimation) {
18→      setAnimatedScore(score);
19→      return;
20→    }
21→    const timer = setTimeout(() => {
22→      setAnimatedScore(score);
23→    }, 100);
24→    return () => clearTimeout(timer);
25→  }, [score, noAnimation]);
26→
27→  const getColor = (s: number) => {
28→    if (s >= 80) return '#a855f7'; // Purple
29→    if (s >= 60) return '#c084fc'; // Light Purple
30→    if (s >= 40) return '#7c3aed'; // Violet
31→    return '#ef4444'; // Red
32→  };
33→
34→  const color = getColor(animatedScore);
35→
36→  return (
37→    <div className="relative flex items-center justify-center" style={{ width: size, height: size }}>
38→      <svg width={size} height={size} className="transform -rotate-90">
39→        {/* Background Ring */}
40→        <circle
41→          cx={size / 2}
42→          cy={size / 2}
43→          r={radius}
44→          stroke="#ffffff"
45→          strokeOpacity="0.1"
46→          strokeWidth={strokeWidth}
47→          fill="transparent"
48→        />
49→        {/* Progress Ring */}
50→        <circle
51→          cx={size / 2}
52→          cy={size / 2}
53→          r={radius}
54→          stroke={color}
55→          strokeWidth={strokeWidth}
56→          fill="transparent"
57→          strokeDasharray={circumference}
58→          strokeDashoffset={offset}
59→          strokeLinecap="round"
60→          className={noAnimation ? '' : "transition-all duration-1000 ease-out"}
61→        />
62→      </svg>
63→      <div className="absolute flex flex-col items-center">
64→        <span className="text-3xl font-bold font-serif" style={{ color }}>{animatedScore}</span>
65→        <span className="text-xs text-gray-400 uppercase tracking-wider">AEO Score</span>
66→      </div>
67→    </div>
68→  );
69→};
70→
71→export default ScoreRing;

